import React from "react";
import {Box, Grid, Card, CardMedia, CardContent, CardHeader } from "@material-ui/core";
import imageUrl from "../../../src/comp/img/oldSite.png";

class Work extends React.Component {
  render() {
    return (
        <Box height={"100%"} p={2} border={1} id="work" style={{backgroundColor:"yellow"}}>
          <Grid container spacing={3} alignItems="center" justify="center" style={{height:"100%"}}>
            <Grid item md={5}> 
              <Card>
              <CardHeader title="Richard Woessner" />
                <CardMedia
                  component="image"
                  image={imageUrl} />
                  <CardContent>
                    sdf
                  </CardContent>
                </Card>
            </Grid>
            <Grid item md={5}>
              <Card style={{height:"20%"}}>sdf</Card>
            </Grid>
          </Grid>
        </Box>
    );
  }
}
export default Work;
